#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=4e6+10;
bool vs[N];int pm[N>>4],cnt,mu[N];long long ph[N];
inline void Init(int mx)
{
	mu[1]=ph[1]=1;rep(2,mx,i)
	{
		if(!vs[i])mu[pm[++cnt]=i]=-1,ph[i]=i-1;
		rep(1,cnt,j)
		{
			if(i*pm[j]>mx)break;vs[i*pm[j]]=1;mu[i*pm[j]]=i%pm[j]==0?0:-mu[i];
			ph[i*pm[j]]=ph[i]*(pm[j]-(i%pm[j]!=0));if(i%pm[j]==0)break;
		}
	}
	rep(1,mx,i)ph[i]+=ph[i-1];
}
inline void Solve(int n)
{
	long long ans=0;for(int l=1,r=0;l<=n;l=r+1)
		{r=n/(n/l);ans+=1ll*(n/l)*(n/l)*(ph[r]-ph[l-1]);}
	printf("%lld\n",(ans-1ll*n*(n+1)/2)/2);
}
int main(){Init(N-10);int n;while(n=read())Solve(n);return 0;}
